mapper.update:
update emp
username = #{username},
name = #{name}, gender = #{gender}, phone = #{phone}, job = #{job}, salary = #{salary}, image = #{image}, entry_date = #{entryDate}, dept_id = #{deptId}, update_time = #{updateTime}
where id = #{id}

mapper.select:
select e.*, d.name dept_name from emp e left join dept d on e.dept_id = d.id


        e.name like concat('%', #{name} ,'%')


        and e.gender = #{gender}


        and e.entry_date between #{begin} and #{end}


where deleted = 0
order by update_time desc
